import { useState, useRef, useCallback, useEffect } from "react";

const LOGO_B64 = "";

const THEMES = {
  "Blue & Dark (Default)": { me:"#3b9eff", them:"#1c1c1e", meText:"#fff", themText:"#fff" },
  "Blue & White":          { me:"#3b9eff", them:"#e5e5ea", meText:"#fff", themText:"#000" },
  "Green & Dark":          { me:"#34c759", them:"#1c1c1e", meText:"#fff", themText:"#fff" },
  "Purple & Dark":         { me:"#8e44ad", them:"#1c1c1e", meText:"#fff", themText:"#fff" },
  "Orange & Dark":         { me:"#e67e22", them:"#1c1c1e", meText:"#fff", themText:"#fff" },
  "Black & White":         { me:"#222",    them:"#f0f0f0", meText:"#fff", themText:"#000" },
  "Pink & Light":          { me:"#e91e8c", them:"#f8d7e3", meText:"#fff", themText:"#222" },
  "Teal & Dark":           { me:"#00897b", them:"#1c1c1e", meText:"#fff", themText:"#fff" },
};

function br(side) {
  return side === "me" ? "18px 18px 4px 18px" : "18px 18px 18px 4px";
}

const DEFAULT_MESSAGES = [
  { id:1, side:"me", text:"brooo", time:null },
  { id:2, side:"me", text:"what would you say?", time:"9:36 PM" },
  { id:3, side:"them", text:"bro", time:null },
  { id:4, side:"them", text:"say this", time:null },
];

// ── Canvas 2D helpers ─────────────────────────────────────────────────────

function roundRect(ctx, x, y, w, h, tl, tr, br, bl) {
  ctx.beginPath();
  ctx.moveTo(x + tl, y);
  ctx.lineTo(x + w - tr, y);
  ctx.quadraticCurveTo(x+w, y, x+w, y+tr);
  ctx.lineTo(x+w, y+h-br);
  ctx.quadraticCurveTo(x+w, y+h, x+w-br, y+h);
  ctx.lineTo(x+bl, y+h);
  ctx.quadraticCurveTo(x, y+h, x, y+h-bl);
  ctx.lineTo(x, y+tl);
  ctx.quadraticCurveTo(x, y, x+tl, y);
  ctx.closePath();
}

function wrapText(ctx, text, maxW) {
  if (!text) return [];
  const words = text.split(' ');
  const lines = [];
  let line = '';
  for (const word of words) {
    const test = line ? line + ' ' + word : word;
    if (ctx.measureText(test).width > maxW && line) { lines.push(line); line = word; }
    else line = test;
  }
  if (line) lines.push(line);
  return lines.length ? lines : [''];
}

// Draw phone handset icon via canvas path
function drawPhoneIcon(ctx, cx, cy, size, color) {
  ctx.save();
  ctx.fillStyle = color;
  ctx.translate(cx - size*0.5, cy - size*0.5);
  ctx.scale(size/18, size/18);
  // Phone path (18x18 grid)
  ctx.beginPath();
  ctx.moveTo(6.6, 10.8);
  ctx.bezierCurveTo(8.0, 13.6, 10.4, 15.9, 13.2, 17.4);
  ctx.lineTo(15.4, 15.2);
  ctx.bezierCurveTo(15.7, 14.9, 16.1, 14.8, 16.4, 15.0);
  ctx.bezierCurveTo(17.5, 15.4, 18.7, 15.6, 20.0, 15.6);
  ctx.bezierCurveTo(20.6, 15.6, 21.0, 16.0, 21.0, 16.6);
  ctx.lineTo(21.0, 20.0);
  ctx.bezierCurveTo(21.0, 20.6, 20.6, 21.0, 20.0, 21.0);
  ctx.bezierCurveTo(10.6, 21.0, 3.0, 13.4, 3.0, 4.0);
  ctx.bezierCurveTo(3.0, 3.4, 3.4, 3.0, 4.0, 3.0);
  ctx.lineTo(7.5, 3.0);
  ctx.bezierCurveTo(8.1, 3.0, 8.5, 3.4, 8.5, 4.0);
  ctx.bezierCurveTo(8.5, 5.3, 8.7, 6.5, 9.1, 7.6);
  ctx.bezierCurveTo(9.3, 7.9, 9.2, 8.3, 8.9, 8.6);
  ctx.closePath();
  ctx.fill();
  ctx.restore();
}

// Draw camera icon
function drawCameraIcon(ctx, cx, cy, size, color) {
  ctx.save();
  ctx.fillStyle = color;
  ctx.translate(cx - size*0.6, cy - size*0.4);
  // Camera body
  roundRect(ctx, 0, size*0.2, size*1.2, size*0.8, size*0.15, size*0.15, size*0.15, size*0.15);
  ctx.fill();
  // Lens
  ctx.beginPath();
  ctx.arc(size*0.6, size*0.6, size*0.25, 0, Math.PI*2);
  ctx.fillStyle = color === '#fff' ? '#000' : '#fff';
  ctx.fill();
  ctx.beginPath();
  ctx.arc(size*0.6, size*0.6, size*0.15, 0, Math.PI*2);
  ctx.fillStyle = color;
  ctx.fill();
  // Viewfinder bump
  ctx.fillStyle = color;
  roundRect(ctx, size*0.35, 0, size*0.5, size*0.25, size*0.1, size*0.1, 0, 0);
  ctx.fill();
  ctx.restore();
}

async function drawChat({ messages, dateStr, showUsername, theme }) {
  const S = 2;
  const W = 390;
  const FONT = `-apple-system, "Helvetica Neue", Arial, sans-serif`;
  const clr = THEMES[theme] || THEMES["Blue & Dark (Default)"];
  const PAD = 12 * S;
  const BUBBLE_MAX_W = Math.floor(W * 0.72) * S;
  const FONT_SIZE = 15 * S;
  const LINE_H = FONT_SIZE * 1.4;
  const BUB_PAD_H = 12 * S;
  const BUB_PAD_V = 9 * S;
  const RADIUS = 18 * S;
  const TAIL = 4 * S;
  const WS = W * S;

  // ── Pre-load ALL images (logo + message images) in parallel ──────────────
  const logoImg = await new Promise(res => {
    const img = new Image();
    img.onload = () => res(img);
    img.onerror = () => res(null);
    img.crossOrigin = 'anonymous';
    img.src = 'data:image/jpeg;base64,' + LOGO_B64;
  });

  const imageCache = {};
  const msgImgs = messages.filter(m => m.image);
  await Promise.all(msgImgs.map(m => new Promise(res => {
    const img = new Image();
    img.onload  = () => { imageCache[m.id] = img; res(); };
    img.onerror = () => res();
    img.crossOrigin = 'anonymous';
    img.src = m.image;
  })));

  // ── Measure canvas using a temp context ───────────────────────────────────
  const tmp = document.createElement('canvas');
  tmp.width = WS; tmp.height = 10;
  const mctx = tmp.getContext('2d');
  mctx.font = `${FONT_SIZE}px ${FONT}`;

  // For each message compute: bubW, bubH, lines, imgDrawH
  const layouts = messages.map(m => {
    const img = imageCache[m.id] || null;
    let imgDrawW = 0, imgDrawH = 0;
    if (img) {
      imgDrawW = BUBBLE_MAX_W - BUB_PAD_H * 2;
      imgDrawH = imgDrawW * (img.naturalHeight / img.naturalWidth);
    }
    mctx.font = `${FONT_SIZE}px ${FONT}`;
    const innerW = BUBBLE_MAX_W - BUB_PAD_H * 2;
    const lines = wrapText(mctx, m.text || '', innerW);
    const textH = m.text ? lines.length * LINE_H : 0;
    const imgGap = img && m.text ? 6 * S : 0;
    const contentH = imgDrawH + imgGap + textH;
    // Bubble width: for text-only single line shrink to fit; for image use max
    let bubW;
    if (img) {
      bubW = BUBBLE_MAX_W;
    } else if (lines.length === 1) {
      bubW = Math.min(mctx.measureText(lines[0]).width + BUB_PAD_H * 2 + 6 * S, BUBBLE_MAX_W);
    } else {
      bubW = BUBBLE_MAX_W;
    }
    const bubH = BUB_PAD_V * 2 + contentH;
    return { ...m, lines, bubW, bubH, imgDrawW, imgDrawH, imgGap, img };
  });

  // ── Compute total canvas height ───────────────────────────────────────────
  const HDR_H  = 58 * S;
  const DATE_H = 36 * S;
  const INP_H  = 54 * S;
  const TAB_H  = 58 * S;
  let msgH = 0;
  let pi = 0;
  while (pi < layouts.length) {
    const l = layouts[pi];
    if (l.side === 'them') {
      // username label
      if (showUsername && l.username && (pi === 0 || layouts[pi-1].side !== 'them')) msgH += 18 * S;
      msgH += l.bubH + 4 * S;
      if (l.time) msgH += 16 * S;
      pi++;
    } else {
      msgH += l.bubH + 4 * S;
      if (l.time) msgH += 16 * S;
      msgH += 4 * S;
      pi++;
    }
  }
  const totalH = HDR_H + DATE_H + msgH + 12 * S + INP_H + TAB_H;

  // ── Create canvas ─────────────────────────────────────────────────────────
  const canvas = document.createElement('canvas');
  canvas.width = WS; canvas.height = totalH;
  const ctx = canvas.getContext('2d');
  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = 'high';

  // BG
  ctx.fillStyle = '#000'; ctx.fillRect(0, 0, WS, totalH);

  // ── HEADER ───────────────────────────────────────────────────────────────
  // separator
  ctx.fillStyle = '#1e1e1e'; ctx.fillRect(0, HDR_H - S, WS, S);

  // Back arrow
  ctx.fillStyle = '#3b9eff';
  ctx.font = `bold ${20*S}px ${FONT}`;
  ctx.textBaseline = 'middle';
  ctx.textAlign = 'left';
  ctx.fillText('←', 18*S, HDR_H/2);

  // Logo circle (clipped)
  const LOGO_R = 15 * S;
  const LOGO_CX = (W/2 - 52) * S;
  const LOGO_CY = HDR_H / 2;
  if (logoImg) {
    ctx.save();
    ctx.beginPath();
    ctx.arc(LOGO_CX, LOGO_CY, LOGO_R, 0, Math.PI*2);
    ctx.clip();
    ctx.drawImage(logoImg, LOGO_CX-LOGO_R, LOGO_CY-LOGO_R, LOGO_R*2, LOGO_R*2);
    ctx.restore();
  }

  // "Vicinity Chat"
  ctx.fillStyle = '#fff';
  ctx.font = `600 ${17*S}px ${FONT}`;
  ctx.textBaseline = 'middle';
  ctx.textAlign = 'left';
  ctx.fillText('Vicinity Chat', LOGO_CX + LOGO_R + 8*S, LOGO_CY);

  // Camera icon (top right)
  drawCameraIcon(ctx, (W - 52) * S, LOGO_CY, 11 * S, '#fff');

  // Phone icon (top right)
  drawPhoneIcon(ctx, (W - 22) * S, LOGO_CY, 11 * S, '#fff');

  // ── DATE ─────────────────────────────────────────────────────────────────
  let curY = HDR_H;
  ctx.fillStyle = '#666';
  ctx.font = `${13*S}px ${FONT}`;
  ctx.textBaseline = 'middle';
  ctx.textAlign = 'center';
  ctx.fillText(dateStr, WS/2, curY + DATE_H/2);
  curY += DATE_H;

  // ── MESSAGES ─────────────────────────────────────────────────────────────
  ctx.textAlign = 'left';
  let li2 = 0;
  while (li2 < layouts.length) {
    const lay = layouts[li2];

    // Username label for first "them" in a run
    if (lay.side === 'them' && showUsername && lay.username) {
      const prevIsThem = li2 > 0 && layouts[li2-1].side === 'them';
      if (!prevIsThem) {
        ctx.fillStyle = '#888';
        ctx.font = `${12*S}px ${FONT}`;
        ctx.textBaseline = 'alphabetic';
        ctx.textAlign = 'left';
        ctx.fillText(lay.username, PAD + 4*S, curY + 13*S);
        curY += 18*S;
      }
    }

    const { bubW, bubH, lines, img, imgDrawW, imgDrawH, imgGap } = lay;
    const isMe = lay.side === 'me';
    const bubX = isMe ? WS - PAD - bubW : PAD;
    const bgColor = isMe ? clr.me : clr.them;
    const txtColor = isMe ? clr.meText : clr.themText;

    // Draw bubble shape
    ctx.fillStyle = bgColor;
    if (isMe) {
      roundRect(ctx, bubX, curY, bubW, bubH, RADIUS, RADIUS, TAIL, RADIUS);
    } else {
      roundRect(ctx, bubX, curY, bubW, bubH, RADIUS, RADIUS, RADIUS, TAIL);
    }
    ctx.fill();

    // Draw image inside bubble
    let contentOffY = BUB_PAD_V;
    if (img && imgDrawH > 0) {
      const imgX = bubX + BUB_PAD_H;
      const imgY = curY + contentOffY;
      // Clip to image region with slight rounding
      ctx.save();
      roundRect(ctx, imgX, imgY, imgDrawW, imgDrawH, 8*S, 8*S, 8*S, 8*S);
      ctx.clip();
      ctx.drawImage(img, imgX, imgY, imgDrawW, imgDrawH);
      ctx.restore();
      contentOffY += imgDrawH + imgGap;
    }

    // Draw text inside bubble
    if (lay.text && lines.length) {
      ctx.fillStyle = txtColor;
      ctx.font = `${FONT_SIZE}px ${FONT}`;
      ctx.textBaseline = 'alphabetic';
      ctx.textAlign = 'left';
      lines.forEach((ln, i) => {
        ctx.fillText(ln, bubX + BUB_PAD_H, curY + contentOffY + FONT_SIZE + i * LINE_H);
      });
    }

    curY += bubH + 4*S;

    // Timestamp
    if (lay.time) {
      ctx.fillStyle = '#555';
      ctx.font = `${11*S}px ${FONT}`;
      ctx.textBaseline = 'alphabetic';
      if (isMe) {
        ctx.textAlign = 'right';
        ctx.fillText(lay.time, WS - PAD - 4*S, curY + 12*S);
        ctx.textAlign = 'left';
      } else {
        ctx.fillText(lay.time, PAD + 4*S, curY + 12*S);
      }
      curY += 16*S;
    }
    if (isMe) curY += 4*S;
    li2++;
  }

  curY += 12*S;

  // ── INPUT BAR ────────────────────────────────────────────────────────────
  ctx.fillStyle = '#1e1e1e'; ctx.fillRect(0, curY, WS, S);
  const ibTop = curY + S;
  const ibMid = ibTop + INP_H/2;

  // + button circle
  ctx.strokeStyle = '#666'; ctx.lineWidth = 1.5*S;
  ctx.beginPath(); ctx.arc(22*S, ibMid, 14*S, 0, Math.PI*2); ctx.stroke();
  ctx.fillStyle = '#ccc';
  ctx.font = `${18*S}px ${FONT}`; ctx.textBaseline = 'middle'; ctx.textAlign = 'center';
  ctx.fillText('+', 22*S, ibMid);

  // Lightning bolt
  ctx.fillStyle = '#888';
  ctx.font = `${14*S}px ${FONT}`; ctx.textBaseline = 'middle'; ctx.textAlign = 'left';
  ctx.fillText('⚡', 42*S, ibMid);

  // Message input box
  const boxX = 62*S, boxH2 = 36*S, boxY = ibMid - boxH2/2, boxW = WS - boxX - 46*S;
  ctx.fillStyle = '#1c1c1e';
  roundRect(ctx, boxX, boxY, boxW, boxH2, 18*S, 18*S, 18*S, 18*S); ctx.fill();
  ctx.strokeStyle = '#3b9eff'; ctx.lineWidth = 1.5*S;
  ctx.stroke();
  ctx.fillStyle = '#555';
  ctx.font = `${14*S}px ${FONT}`; ctx.textBaseline = 'middle'; ctx.textAlign = 'left';
  ctx.fillText('Send a message', boxX + 16*S, ibMid);

  // Send button
  ctx.fillStyle = '#3b9eff';
  ctx.beginPath(); ctx.arc(WS - 20*S, ibMid, 15*S, 0, Math.PI*2); ctx.fill();
  // Arrow ▶
  ctx.fillStyle = '#fff';
  ctx.beginPath();
  ctx.moveTo(WS - 26*S, ibMid - 7*S);
  ctx.lineTo(WS - 26*S, ibMid + 7*S);
  ctx.lineTo(WS - 13*S, ibMid);
  ctx.closePath(); ctx.fill();

  curY = ibTop + INP_H;

  // ── TAB BAR ──────────────────────────────────────────────────────────────
  ctx.fillStyle = '#1e1e1e'; ctx.fillRect(0, curY, WS, S); curY += S;
  const tabW = WS / 4;
  const tabMid = curY + 20*S;
  const tabLabels = ['Home','Nearby','Chats','Profile'];
  const tabColors = ['#555','#555','#3b9eff','#555'];

  // Home icon (house)
  const drawHome = (cx) => {
    ctx.beginPath();
    ctx.moveTo(cx, tabMid-8*S);
    ctx.lineTo(cx-8*S, tabMid);
    ctx.lineTo(cx+8*S, tabMid);
    ctx.closePath(); ctx.fill();
    ctx.fillRect(cx-5*S, tabMid, 10*S, 7*S);
    // door
    ctx.fillStyle = '#000';
    ctx.fillRect(cx-2*S, tabMid+3*S, 4*S, 4*S);
    ctx.fillStyle = '#555';
  };
  // Globe icon
  const drawGlobe = (cx) => {
    ctx.beginPath(); ctx.arc(cx, tabMid, 8*S, 0, Math.PI*2); ctx.stroke();
    ctx.beginPath(); ctx.ellipse(cx, tabMid, 4*S, 8*S, 0, 0, Math.PI*2); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(cx-8*S, tabMid); ctx.lineTo(cx+8*S, tabMid); ctx.stroke();
  };
  // Chat icon
  const drawChat2 = (cx) => {
    roundRect(ctx, cx-8*S, tabMid-7*S, 16*S, 11*S, 2*S, 2*S, 2*S, 2*S); ctx.stroke();
    ctx.beginPath(); ctx.arc(cx-3*S, tabMid-1*S, 1.2*S, 0, Math.PI*2); ctx.fill();
    ctx.beginPath(); ctx.arc(cx, tabMid-1*S, 1.2*S, 0, Math.PI*2); ctx.fill();
    ctx.beginPath(); ctx.arc(cx+3*S, tabMid-1*S, 1.2*S, 0, Math.PI*2); ctx.fill();
  };
  // Smiley icon
  const drawFace = (cx) => {
    ctx.beginPath(); ctx.arc(cx, tabMid, 8*S, 0, Math.PI*2); ctx.stroke();
    ctx.beginPath(); ctx.arc(cx-2.5*S, tabMid-2*S, 1*S, 0, Math.PI*2); ctx.fill();
    ctx.beginPath(); ctx.arc(cx+2.5*S, tabMid-2*S, 1*S, 0, Math.PI*2); ctx.fill();
    ctx.beginPath(); ctx.arc(cx, tabMid+1*S, 3*S, 0.1, Math.PI-0.1); ctx.stroke();
  };

  tabLabels.forEach((lbl, ti) => {
    const cx = tabW * ti + tabW/2;
    ctx.strokeStyle = tabColors[ti]; ctx.fillStyle = tabColors[ti];
    ctx.lineWidth = 1.5*S;
    if (ti===0) drawHome(cx);
    else if (ti===1) drawGlobe(cx);
    else if (ti===2) drawChat2(cx);
    else drawFace(cx);
    ctx.font = `${10*S}px ${FONT}`; ctx.textBaseline = 'alphabetic';
    ctx.textAlign = 'center';
    ctx.fillStyle = tabColors[ti];
    ctx.fillText(lbl, cx, curY + 40*S);
  });

  return canvas;
}

export default function VicinityChat() {
  const [messages, setMessages]         = useState(DEFAULT_MESSAGES);
  
  useEffect(() => {
    const disableContextMenu = (e) => e.preventDefault();
    const disableInspect = (e) => {
      if (
        e.key === 'F12' ||
        (e.ctrlKey && e.shiftKey && ['I','J','C'].includes(e.key.toUpperCase())) ||
        (e.ctrlKey && e.key.toUpperCase() === 'U')
      ) {
        e.preventDefault();
      }
    };

    document.addEventListener('contextmenu', disableContextMenu);
    document.addEventListener('keydown', disableInspect);

    return () => {
      document.removeEventListener('contextmenu', disableContextMenu);
      document.removeEventListener('keydown', disableInspect);
    };
  }, []);
  const [dateStr, setDateStr]           = useState("06/13/2026");
  const [showUsername, setShowUsername] = useState(true);
  const [theme, setTheme]               = useState("Blue & Dark (Default)");
  const [showModal, setShowModal]       = useState(false);
  const [editId, setEditId]             = useState(null);
  const [editText, setEditText]         = useState("");
  const [downloading, setDownloading]   = useState(false);
  const [newMsg, setNewMsg]             = useState({ side:"me", text:"", time:"", username:"Yeklaw", image:null });

  const endRef      = useRef(null);
  const fileInputRef = useRef(null);
  const nextId      = useRef(20);

  const clr = THEMES[theme];

  const deleteMsg = id => setMessages(p => p.filter(m => m.id !== id));
  const moveMsg   = (id, dir) => setMessages(p => {
    const i = p.findIndex(m => m.id === id);
    if (dir === "up"   && i === 0)          return p;
    if (dir === "down" && i === p.length-1) return p;
    const n = [...p]; const j = dir==="up"?i-1:i+1;
    [n[i],n[j]] = [n[j],n[i]]; return n;
  });
  const startEdit = m => { setEditId(m.id); setEditText(m.text); };
  const saveEdit  = ()  => {
    setMessages(p => p.map(m => m.id===editId ? {...m,text:editText} : m));
    setEditId(null); setEditText("");
  };
  const addMessage = () => {
    if (!newMsg.text.trim() && !newMsg.image) return;
    const id = nextId.current++;
    setMessages(p => [...p, {
      id, side:newMsg.side, text:newMsg.text,
      time:newMsg.time||null,
      username:newMsg.side==="them"?(newMsg.username||"Yeklaw"):undefined,
      image:newMsg.image||null,
    }]);
    setNewMsg({ side:"me", text:"", time:"", username:"Yeklaw", image:null });
    setShowModal(false);
    setTimeout(() => endRef.current?.scrollIntoView({ behavior:"smooth" }), 60);
  };
  const pickImage = e => {
    const file = e.target.files[0]; if (!file) return;
    const r = new FileReader();
    r.onload = ev => setNewMsg(p => ({...p, image:ev.target.result}));
    r.readAsDataURL(file);
  };

  const downloadScreenshot = useCallback(async () => {
    if (downloading) return;
    setDownloading(true);
    try {
      const canvas = await drawChat({ messages, dateStr, showUsername, theme });
      const link = document.createElement("a");
      link.download = "vicinity-chat.png";
      link.href = canvas.toDataURL("image/png");
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } catch(e) { console.error(e); }
    setDownloading(false);
  }, [messages, dateStr, showUsername, theme, downloading]);

  const renderMsgs = () => {
    const out = [];
    let i = 0;
    while (i < messages.length) {
      const msg = messages[i];
      if (msg.side === "them") {
        const grp = [];
        while (i < messages.length && messages[i].side === "them") { grp.push(messages[i]); i++; }
        out.push(
          <div key={"g"+grp[0].id} style={{ alignSelf:"flex-start", maxWidth:"74%", marginBottom:4, display:"flex", flexDirection:"column" }}>
            {grp.map((m, mi) => (
              <div key={m.id} style={{ marginBottom:2 }}>
                {mi===0 && showUsername && m.username && (
                  <div style={{ color:"#888", fontSize:12, marginBottom:2, marginLeft:4 }}>{m.username}</div>
                )}
                <div className="bwrap" style={{ position:"relative", display:"inline-block" }}>
                  {editId===m.id ? (
                    <div style={{ display:"flex", gap:4 }}>
                      <input value={editText} onChange={e=>setEditText(e.target.value)} autoFocus
                        style={{ flex:1, background:"#333", color:"#fff", border:"1px solid #555", borderRadius:16, padding:"8px 12px", fontSize:15, fontFamily:"inherit" }}/>
                      <button onClick={saveEdit} style={{ background:clr.me, border:"none", borderRadius:8, color:"#fff", padding:"4px 10px", cursor:"pointer" }}>✓</button>
                    </div>
                  ) : (
                    <div onDoubleClick={()=>startEdit(m)} style={{
                      background:clr.them, color:clr.themText,
                      borderRadius:br("them"), padding:"8px 14px",
                      fontSize:15, lineHeight:1.4, wordBreak:"break-word",
                    }}>
                      {m.image && <img src={m.image} alt="" style={{ maxWidth:"100%", borderRadius:10, display:"block", marginBottom:m.text?6:0 }}/>}
                      {m.text}
                    </div>
                  )}
                  <button className="ctrl-btn" onClick={()=>deleteMsg(m.id)}
                    style={{ position:"absolute", top:-8, right:-8, background:"#ff3b30", border:"none",
                    borderRadius:"50%", color:"#fff", width:20, height:20, fontSize:12, cursor:"pointer",
                    display:"flex", alignItems:"center", justifyContent:"center", zIndex:10 }}>×</button>
                  <div className="ctrl-btn" style={{ position:"absolute", top:"50%", transform:"translateY(-50%)", right:-52, display:"flex", flexDirection:"column", gap:2 }}>
                    <button onClick={()=>moveMsg(m.id,"up")} style={{ background:"#333", border:"none", borderRadius:6, color:"#fff", width:22, height:22, fontSize:10, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>▲</button>
                    <button onClick={()=>moveMsg(m.id,"down")} style={{ background:"#333", border:"none", borderRadius:6, color:"#fff", width:22, height:22, fontSize:10, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>▼</button>
                  </div>
                </div>
                {m.time && <div style={{ color:"#555", fontSize:11, marginTop:2, marginLeft:4 }}>{m.time}</div>}
              </div>
            ))}
          </div>
        );
      } else {
        const m = messages[i]; i++;
        out.push(
          <div key={m.id} style={{ alignSelf:"flex-end", maxWidth:"74%", marginBottom:4 }}>
            <div className="bwrap" style={{ position:"relative", display:"inline-block", float:"right", clear:"both" }}>
              {editId===m.id ? (
                <div style={{ display:"flex", gap:4 }}>
                  <input value={editText} onChange={e=>setEditText(e.target.value)} autoFocus
                    style={{ flex:1, background:clr.me, color:clr.meText, border:"none", borderRadius:16, padding:"8px 12px", fontSize:15, fontFamily:"inherit" }}/>
                  <button onClick={saveEdit} style={{ background:clr.me, border:"none", borderRadius:8, color:"#fff", padding:"4px 10px", cursor:"pointer" }}>✓</button>
                </div>
              ) : (
                <div onDoubleClick={()=>startEdit(m)} style={{
                  background:clr.me, color:clr.meText,
                  borderRadius:br("me"), padding:"8px 14px",
                  fontSize:15, lineHeight:1.4, wordBreak:"break-word",
                }}>
                  {m.image && <img src={m.image} alt="" style={{ maxWidth:"100%", borderRadius:10, display:"block", marginBottom:m.text?6:0 }}/>}
                  {m.text}
                </div>
              )}
              <button className="ctrl-btn" onClick={()=>deleteMsg(m.id)}
                style={{ position:"absolute", top:-8, left:-8, background:"#ff3b30", border:"none",
                borderRadius:"50%", color:"#fff", width:20, height:20, fontSize:12, cursor:"pointer",
                display:"flex", alignItems:"center", justifyContent:"center", zIndex:10 }}>×</button>
              <div className="ctrl-btn" style={{ position:"absolute", top:"50%", transform:"translateY(-50%)", left:-52, display:"flex", flexDirection:"column", gap:2 }}>
                <button onClick={()=>moveMsg(m.id,"up")} style={{ background:"#333", border:"none", borderRadius:6, color:"#fff", width:22, height:22, fontSize:10, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>▲</button>
                <button onClick={()=>moveMsg(m.id,"down")} style={{ background:"#333", border:"none", borderRadius:6, color:"#fff", width:22, height:22, fontSize:10, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>▼</button>
              </div>
            </div>
            {m.time && <div style={{ color:"#555", fontSize:11, marginTop:2, textAlign:"right", clear:"both" }}>{m.time}</div>}
          </div>
        );
      }
    }
    return out;
  };

  return (
    <>
      <style>{`
        .bwrap .ctrl-btn { opacity:0; pointer-events:none; transition:opacity 0.15s; }
        .bwrap:hover .ctrl-btn { opacity:1; pointer-events:auto; }
        * { box-sizing:border-box; }
      `}</style>
      <div style={{ display:"flex", justifyContent:"center", alignItems:"flex-start", minHeight:"100vh",
        background:"#111", fontFamily:"-apple-system,BlinkMacSystemFont,'SF Pro Text',sans-serif",
        padding:"30px 16px", gap:20, flexWrap:"wrap" }}>

        {/* PHONE */}
        <div style={{ width:390, height:844, background:"#000", borderRadius:44,
          border:"2px solid #2a2a2a", overflow:"hidden", display:"flex", flexDirection:"column",
          flexShrink:0, boxShadow:"0 24px 64px rgba(0,0,0,0.9)" }}>

          {/* Header */}
          <div style={{ background:"#000", padding:"14px 20px 10px", display:"flex",
            alignItems:"center", justifyContent:"space-between", borderBottom:"0.5px solid #1e1e1e", flexShrink:0 }}>
            <span style={{ color:"#3b9eff", fontSize:22, lineHeight:1 }}>←</span>
            <div style={{ display:"flex", alignItems:"center", gap:8 }}>
              <img src={"data:image/jpeg;base64,"+LOGO_B64} style={{ width:32, height:32, borderRadius:"50%", objectFit:"cover" }} alt=""/>
              <span style={{ color:"#fff", fontWeight:600, fontSize:17, letterSpacing:-0.3 }}>Vicinity Chat</span>
            </div>
            <div style={{ display:"flex", gap:16, alignItems:"center" }}>
              <svg width="22" height="16" viewBox="0 0 22 16"><rect x="0" y="2" width="14" height="12" rx="2" fill="white"/><polygon points="14,5 21,1 21,15 14,11" fill="white"/></svg>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="white"><path d="M6.6 10.8c1.4 2.8 3.8 5.1 6.6 6.6l2.2-2.2c.3-.3.7-.4 1-.2 1.1.4 2.3.6 3.6.6.6 0 1 .4 1 1V20c0 .6-.4 1-1 1-9.4 0-17-7.6-17-17 0-.6.4-1 1-1h3.5c.6 0 1 .4 1 1 0 1.3.2 2.5.6 3.6.1.3 0 .7-.2 1L6.6 10.8z"/></svg>
            </div>
          </div>

          {/* Messages */}
          <div style={{ flex:1, overflowY:"auto", padding:"0 12px 8px",
            display:"flex", flexDirection:"column", gap:2, background:"#000" }}>
            <div style={{ textAlign:"center", padding:"10px 0 8px" }}>
              <span style={{ color:"#666", fontSize:13 }}>{dateStr}</span>
            </div>
            {renderMsgs()}
            <div ref={endRef}/>
          </div>

          {/* Input bar */}
          <div style={{ background:"#000", padding:"10px 12px", display:"flex",
            alignItems:"center", gap:8, borderTop:"0.5px solid #1e1e1e", flexShrink:0 }}>
            <div onClick={()=>setShowModal(true)} style={{ width:34, height:34, borderRadius:"50%",
              border:"2px solid #555", display:"flex", alignItems:"center", justifyContent:"center",
              color:"#fff", fontSize:20, lineHeight:1, cursor:"pointer", flexShrink:0 }}>+</div>
            <svg width="18" height="22" viewBox="0 0 14 22" fill="#888" style={{ flexShrink:0 }}>
              <polygon points="8,0 0,13 6,13 6,22 14,9 8,9"/>
            </svg>
            <div onClick={()=>setShowModal(true)} style={{ flex:1, background:"#1c1c1e",
              border:"1.5px solid #3b9eff", borderRadius:22, padding:"9px 16px",
              color:"#555", fontSize:15, cursor:"text" }}>Send a message</div>
            <div onClick={()=>setShowModal(true)} style={{ width:36, height:36, borderRadius:"50%",
              background:"#3b9eff", display:"flex", alignItems:"center", justifyContent:"center",
              cursor:"pointer", flexShrink:0 }}>
              <svg width="14" height="14" viewBox="0 0 24 24"><polygon points="4,20 20,12 4,4 8,12" fill="white"/></svg>
            </div>
          </div>

          {/* Tab bar */}
          <div style={{ background:"#000", borderTop:"0.5px solid #1e1e1e", display:"flex",
            justifyContent:"space-around", padding:"8px 0 16px", flexShrink:0 }}>
            {[
              { label:"Home",    active:false, icon:<svg width="24" height="24" viewBox="0 0 24 24" fill="none"><path d="M5 9l7-6 7 6v11H15v-5H9v5H5V9z" stroke="#555" strokeWidth="1.5"/></svg> },
              { label:"Nearby",  active:false, icon:<svg width="24" height="24" viewBox="0 0 24 24" fill="none"><circle cx="12" cy="12" r="9" stroke="#555" strokeWidth="1.5"/><ellipse cx="12" cy="12" rx="4" ry="9" stroke="#555" strokeWidth="1.5"/><line x1="3" y1="12" x2="21" y2="12" stroke="#555" strokeWidth="1.5"/></svg> },
              { label:"Chats",   active:true,  icon:<svg width="24" height="24" viewBox="0 0 24 24" fill="none"><rect x="4" y="4" width="16" height="13" rx="2" stroke="#3b9eff" strokeWidth="1.5"/><circle cx="9" cy="11" r="1.2" fill="#3b9eff"/><circle cx="12" cy="11" r="1.2" fill="#3b9eff"/><circle cx="15" cy="11" r="1.2" fill="#3b9eff"/></svg> },
              { label:"Profile", active:false, icon:<svg width="24" height="24" viewBox="0 0 24 24" fill="none"><circle cx="12" cy="12" r="9" stroke="#555" strokeWidth="1.5"/><circle cx="9" cy="10" r="1" fill="#555"/><circle cx="15" cy="10" r="1" fill="#555"/><path d="M9 15 Q12 17.5 15 15" stroke="#555" strokeWidth="1.5" strokeLinecap="round"/></svg> },
            ].map(t => (
              <div key={t.label} style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:2, cursor:"pointer" }}>
                {t.icon}
                <span style={{ color:t.active?"#3b9eff":"#555", fontSize:10 }}>{t.label}</span>
              </div>
            ))}
          </div>
        </div>

        {/* CONTROLS */}
        <div style={{ width:270, display:"flex", flexDirection:"column", gap:10 }}>
          <div style={{ color:"#fff", fontWeight:700, fontSize:15, marginBottom:2 }}>⚙️ Controls</div>

          <button onClick={()=>setShowModal(true)} style={{ background:"#3b9eff", border:"none",
            borderRadius:12, color:"#fff", padding:"11px", fontSize:14, fontWeight:600, cursor:"pointer" }}>
            + Add Message
          </button>

          <button onClick={downloadScreenshot} disabled={downloading}
            style={{ background:"#1c1c1e", border:"1px solid #444", borderRadius:12, color:"#fff",
            padding:"11px", fontSize:14, cursor:"pointer", display:"flex", alignItems:"center",
            justifyContent:"center", gap:8, opacity:downloading?0.6:1 }}>
            <svg width="16" height="16" viewBox="0 0 24 24" stroke="white" strokeWidth="2" fill="none">
              <path d="M12 3v13M8 12l4 4 4-4"/><path d="M5 20h14"/>
            </svg>
            {downloading ? "Generating…" : "Download Screenshot"}
          </button>

          <div style={{ background:"#1c1c1e", border:"1px solid #2a2a2a", borderRadius:12,
            padding:"11px 14px", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
            <span style={{ color:"#ccc", fontSize:13 }}>Show Username</span>
            <div onClick={()=>setShowUsername(p=>!p)} style={{ width:44, height:24, borderRadius:12,
              background:showUsername?"#3b9eff":"#555", cursor:"pointer", position:"relative", transition:"background 0.2s" }}>
              <div style={{ position:"absolute", top:2, left:showUsername?22:2, width:20, height:20,
                borderRadius:"50%", background:"#fff", transition:"left 0.2s" }}/>
            </div>
          </div>

          <div style={{ background:"#1c1c1e", border:"1px solid #2a2a2a", borderRadius:12, padding:"11px 14px" }}>
            <div style={{ color:"#888", fontSize:11, marginBottom:5 }}>Date Header</div>
            <input value={dateStr} onChange={e=>setDateStr(e.target.value)}
              style={{ width:"100%", background:"#2c2c2e", color:"#fff", border:"1px solid #444",
              borderRadius:8, padding:"7px 11px", fontSize:14, fontFamily:"inherit" }}/>
          </div>

          <div style={{ background:"#1c1c1e", border:"1px solid #2a2a2a", borderRadius:12, padding:"11px 14px" }}>
            <div style={{ color:"#888", fontSize:11, marginBottom:8 }}>Bubble Color Theme</div>
            <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
              {Object.keys(THEMES).map(t => (
                <div key={t} onClick={()=>setTheme(t)} style={{ display:"flex", alignItems:"center", gap:9,
                  cursor:"pointer", padding:"5px 7px", borderRadius:8,
                  background:theme===t?"#2c2c2e":"transparent",
                  border:theme===t?"1px solid #555":"1px solid transparent" }}>
                  <div style={{ display:"flex", gap:3 }}>
                    <div style={{ width:14, height:14, borderRadius:"50%", background:THEMES[t].me, border:"1px solid #444" }}/>
                    <div style={{ width:14, height:14, borderRadius:"50%", background:THEMES[t].them, border:"1px solid #444" }}/>
                  </div>
                  <span style={{ color:theme===t?"#fff":"#999", fontSize:12 }}>{t}</span>
                </div>
              ))}
            </div>
          </div>

          <div style={{ color:"#555", fontSize:11, lineHeight:1.7 }}>
            💬 Click + or input bar to add<br/>
            ✏️ Double-tap bubble to edit<br/>
            ↕️ Hover → ▲▼ to reorder<br/>
            🗑️ Hover → × to delete
          </div>
        </div>

        {/* MODAL */}
        {showModal && (
          <div onClick={e=>{ if(e.target===e.currentTarget) setShowModal(false); }}
            style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.85)",
            display:"flex", alignItems:"center", justifyContent:"center", zIndex:300 }}>
            <div style={{ background:"#1c1c1e", borderRadius:20, padding:22, width:340,
              display:"flex", flexDirection:"column", gap:12, border:"1px solid #333",
              maxHeight:"90vh", overflowY:"auto" }}>
              <div style={{ color:"#fff", fontSize:17, fontWeight:600, textAlign:"center" }}>Add Message</div>
              <div style={{ display:"flex", gap:8 }}>
                {["me","them"].map(s=>(
                  <button key={s} onClick={()=>setNewMsg(p=>({...p,side:s}))} style={{
                    flex:1, padding:"9px", borderRadius:10,
                    background:newMsg.side===s?"#3b9eff":"#2c2c2e",
                    color:"#fff", border:"none", cursor:"pointer", fontSize:14, fontWeight:500 }}>
                    {s==="me"?"My Side →":"← Their Side"}
                  </button>
                ))}
              </div>
              {newMsg.side==="them" && (
                <input value={newMsg.username} onChange={e=>setNewMsg(p=>({...p,username:e.target.value}))}
                  placeholder="Username (e.g. Yeklaw)"
                  style={{ background:"#2c2c2e", color:"#fff", border:"1px solid #444",
                  borderRadius:12, padding:"9px 13px", fontSize:14, fontFamily:"inherit" }}/>
              )}
              <textarea value={newMsg.text} onChange={e=>setNewMsg(p=>({...p,text:e.target.value}))}
                placeholder="Message text…" rows={3}
                style={{ background:"#2c2c2e", color:"#fff", border:"1px solid #444",
                borderRadius:12, padding:"9px 13px", fontSize:14, fontFamily:"inherit", resize:"none" }}/>
              <input value={newMsg.time} onChange={e=>setNewMsg(p=>({...p,time:e.target.value}))}
                placeholder="Time stamp e.g. 9:36 PM — optional"
                style={{ background:"#2c2c2e", color:"#fff", border:"1px solid #444",
                borderRadius:12, padding:"9px 13px", fontSize:14, fontFamily:"inherit" }}/>
              <div>
                <div style={{ color:"#888", fontSize:11, marginBottom:5 }}>Attach Image (optional)</div>
                <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                  <button onClick={()=>fileInputRef.current?.click()}
                    style={{ background:"#2c2c2e", border:"1px dashed #555", borderRadius:10,
                    color:"#aaa", padding:"7px 13px", fontSize:13, cursor:"pointer" }}>📷 Choose</button>
                  {newMsg.image && (
                    <>
                      <img src={newMsg.image} alt="" style={{ width:44, height:44, borderRadius:8, objectFit:"cover" }}/>
                      <button onClick={()=>setNewMsg(p=>({...p,image:null}))}
                        style={{ background:"#ff3b30", border:"none", borderRadius:8, color:"#fff", padding:"4px 9px", fontSize:12, cursor:"pointer" }}>✕</button>
                    </>
                  )}
                  <input ref={fileInputRef} type="file" accept="image/*" onChange={pickImage} style={{ display:"none" }}/>
                </div>
              </div>
              <div style={{ display:"flex", gap:8 }}>
                <button onClick={()=>setShowModal(false)} style={{ flex:1, padding:"10px", borderRadius:12,
                  background:"#2c2c2e", color:"#fff", border:"none", cursor:"pointer", fontSize:14 }}>Cancel</button>
                <button onClick={addMessage} style={{ flex:1, padding:"10px", borderRadius:12,
                  background:"#3b9eff", color:"#fff", border:"none", cursor:"pointer", fontSize:14, fontWeight:600 }}>Add</button>
              </div>
            </div>
          </div>
        )}
      </div>
    </>
  );
}
